  ('disabled-57f41407-moex-00717', 'disabled-57f41407', 'disabled-57f41407-moex-110-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '授益行政處分撤銷時，關於相對人之信賴保護，下列敘述何者錯誤？', '["相對人須對行政處分有信賴表現", "相對人對重要事項提供不正確資料，致使行政機關依該資料作成行政處 分者，信賴不值得保護", "相對人因信賴行政處分而受有損失，行政機關應給予合理補償", "相對人之信賴利益顯然大於撤銷所欲維護之公益時，行政機關仍得撤銷 該行政處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "5db5447f7cf3", "answer_pdf_sha1": "7fcda6220c2a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
